import pytest
import requests

BASE_URL = "<BASE_URL>"

@pytest.fixture
def mid_month_account(seed_account_fixture):
    return seed_account_fixture(balance=5000.00, accrual_days=15, tier="mid")

def test_interest_not_credited_on_non_last_business_day(
    mid_month_account, mid_month_date
):
    account_id = mid_month_account["account_id"]

    resp = requests.post(
        f"{BASE_URL}/cron/interest",
        json={"run_date": mid_month_date},
        headers={"X-Idempotency-Key": f"test-neg-{account_id}"}
    )
    assert resp.status_code in (200, 409, 422)

    if resp.status_code == 200:
        body = resp.json()
        results = body.get("results", [])
        credited = [r for r in results if r.get("account_id") == account_id
                    and r.get("status") == "CREDITED"]
        assert len(credited) == 0, "Interest must not be credited mid-month"

    ledger_resp = requests.get(f"{BASE_URL}/accounts/{account_id}/ledger")
    entries = [e for e in ledger_resp.json()["entries"] if e["type"] == "INTEREST_CREDIT"]
    assert len(entries) == 0, "No INTEREST_CREDIT ledger entry expected mid-month"

import pytest
import requests

BASE_URL = "<BASE_URL>"

@pytest.fixture
def zero_balance_account(seed_account_fixture):
    return seed_account_fixture(balance=0.00, accrual_days=30, tier="lower")

def test_no_interest_credited_for_zero_balance_account(
    zero_balance_account, last_business_day_date
):
    account_id = zero_balance_account["account_id"]

    resp = requests.post(
        f"{BASE_URL}/cron/interest",
        json={"run_date": last_business_day_date},
        headers={"X-Idempotency-Key": f"test-dt-zero-{account_id}"}
    )
    assert resp.status_code == 200

    body = resp.json()
    results = body.get("results", [])
    result = next((r for r in results if r["account_id"] == account_id), None)
    if result:
        assert result["status"] in ("SKIPPED", "ZERO_BALANCE", "NO_CREDIT")

    ledger_resp = requests.get(f"{BASE_URL}/accounts/{account_id}/ledger")
    entries = [e for e in ledger_resp.json()["entries"] if e["type"] == "INTEREST_CREDIT"]
    assert len(entries) == 0, "Zero-balance account must not receive an interest credit"

import pytest
import requests

BASE_URL = "<BASE_URL>"

@pytest.fixture
def cycle_account(seed_account_fixture):
    return seed_account_fixture(balance=2500.00, accrual_days=0, tier="lower")

def get_state(account_id):
    r = requests.get(f"{BASE_URL}/accounts/{account_id}/state")
    assert r.status_code == 200
    return r.json()["state"]

def test_account_state_transitions_through_accrual_and_credit_cycle(
    cycle_account, last_business_day_date, next_month_first_day_date
):
    account_id = cycle_account["account_id"]

    accrual_resp = requests.post(
        f"{BASE_URL}/cron/daily-accrual",
        json={"account_id": account_id, "date": "<first_day_of_month>"},
        headers={"X-Idempotency-Key": f"test-stc-accrual-{account_id}"}
    )
    assert accrual_resp.status_code == 200
    assert get_state(account_id) == "ACCRUING"

    credit_resp = requests.post(
        f"{BASE_URL}/cron/interest",
        json={"run_date": last_business_day_date},
        headers={"X-Idempotency-Key": f"test-stc-credit-{account_id}"}
    )
    assert credit_resp.status_code == 200
    assert get_state(account_id) == "INTEREST_CREDITED"

    next_resp = requests.post(
        f"{BASE_URL}/cron/daily-accrual",
        json={"account_id": account_id, "date": next_month_first_day_date},
        headers={"X-Idempotency-Key": f"test-stc-next-{account_id}"}
    )
    assert next_resp.status_code == 200
    assert get_state(account_id) == "ACCRUING"
